class FileSystem:
    def __init__(self):
        self.root = {"dirs":{}, "files":{}}
    def ls(self, path):
        node = self.root
        if path != "/":
            for p in path.split('/')[1:]:
                if p in node["files"]:
                    return [p]
                node = node["dirs"][p]
        return sorted(list(node["dirs"].keys()) + list(node["files"].keys()))
    def mkdir(self, path):
        node = self.root
        for p in path.split('/')[1:]:
            if p not in node["dirs"]:
                node["dirs"][p] = {"dirs":{}, "files":{}}
            node = node["dirs"][p]
    def addContentToFile(self, filePath, content):
        node = self.root
        parts = filePath.split('/')
        for p in parts[1:-1]:
            node = node["dirs"][p]
        node["files"][parts[-1]] = node["files"].get(parts[-1], "") + content
    def readContentFromFile(self, filePath):
        node = self.root
        parts = filePath.split('/')
        for p in parts[1:-1]:
            node = node["dirs"][p]
        return node["files"][parts[-1]]

def solveFileSystem(commands, args):
    fs = FileSystem()
    res = []
    for cmd, arg in zip(commands, args):
        if cmd == "FileSystem": res.append(None)
        elif cmd == "ls": res.append(fs.ls(arg[0]))
        elif cmd == "mkdir": res.append(fs.mkdir(arg[0]))
        elif cmd == "addContentToFile": res.append(fs.addContentToFile(arg[0], arg[1]))
        elif cmd == "readContentFromFile": res.append(fs.readContentFromFile(arg[0]))
    return res

